import { cn } from '@/utils/cn';
import { getColor } from '@/utils/helper';
import { acquire, OFFSET, release, ZIndex, ZIndexType } from '@components/z-index';
import { cva, VariantProps } from 'class-variance-authority';
import {
  Component,
  createSignal,
  createUniqueId,
  JSX,
  Match,
  mergeProps,
  onCleanup,
  onMount,
  Show,
  Switch,
} from 'solid-js';
import type { TooltipPortalProps, TooltipProps } from './tooltip.types';

// ─── CVA variants (dùng cho TooltipPortal) ────────────────────────────────

const tooltipVariants = cva('', {
  variants: {
    color: {
      neutral: 'tooltip-neutral',
      primary: 'tooltip-primary',
      secondary: 'tooltip-secondary',
      accent: 'tooltip-accent',
      info: 'tooltip-info',
      success: 'tooltip-success',
      warning: 'tooltip-warning',
      error: 'tooltip-error',
    },
    position: {
      top: 'tooltip-top',
      bottom: 'tooltip-bottom',
      right: 'tooltip-right',
      left: 'tooltip-left',
    },
  },
});
export type TooltipVariantsProps = VariantProps<typeof tooltipVariants>;

// ═══════════════════════════════════════════════════════════════════════════
// TOOLTIP — IO-based (không bị clip bởi overflow)
// ═══════════════════════════════════════════════════════════════════════════

// --- Global scope (IO mechanism) ---
type ActiveEntry = {
  node: HTMLDivElement;
  registryKey: string;
  offset: number;
  /** true khi chuột đang ở trên bubble — giữ tooltip không bị remove */
  bubbleHovered: boolean;
  /** position của trigger để tính bridge */
  position: 'top' | 'bottom' | 'left' | 'right';
};

const activeMap = new Map<string, ActiveEntry>();

/** Registry cho customContent: id → rendered DOM node */
const customContentRegistry = new Map<string, Element>();

let refCount = 0;
let observer: IntersectionObserver | null = null;

function calcStyle(
  r: DOMRect,
  position: 'top' | 'bottom' | 'left' | 'right',
): Record<string, string> {
  const OFFSET_PX = 8;
  if (position === 'top') {
    return {
      left: `${r.left + r.width / 2}px`,
      top: `${r.top - OFFSET_PX}px`,
      transform: 'translateX(-50%) translateY(-100%)',
    };
  } else if (position === 'bottom') {
    return {
      left: `${r.left + r.width / 2}px`,
      top: `${r.bottom + OFFSET_PX}px`,
      transform: 'translateX(-50%)',
    };
  } else if (position === 'left') {
    return {
      left: `${r.left - OFFSET_PX}px`,
      top: `${r.top + r.height / 2}px`,
      transform: 'translateX(-100%) translateY(-50%)',
    };
  } else {
    return {
      left: `${r.right + OFFSET_PX}px`,
      top: `${r.top + r.height / 2}px`,
      transform: 'translateY(-50%)',
    };
  }
}

function showTooltip(
  id: string,
  triggerEl: HTMLElement,
  content: string | undefined,
  customContent: Element | undefined,
  position: 'top' | 'bottom' | 'left' | 'right',
  colorClass: string,
  extraClass: string | undefined,
  customZIndex: number | undefined,
) {
  if (activeMap.has(id)) return;

  const r = triggerEl.getBoundingClientRect();
  const style = calcStyle(r, position);

  const node = document.createElement('div');
  node.className = cn('too06', colorClass, extraClass);

  Object.assign(node.style, { position: 'fixed', pointerEvents: 'auto' }, style);

  let registryKey: string;
  let zIndexOffset: number;
  let zIndex: number;

  if (customZIndex !== undefined) {
    zIndex = customZIndex;
    registryKey = '';
    zIndexOffset = -1;
  } else {
    const acquired = acquire(ZIndexType.TOOLTIP, OFFSET[ZIndexType.TOOLTIP]);
    zIndex = acquired.zIndex;
    registryKey = acquired.registryKey;
    zIndexOffset = acquired.offset;
  }

  node.style.zIndex = String(zIndex);

  if (content) {
    node.textContent = content;
  } else if (customContent) {
    node.appendChild(customContent.cloneNode(true));
  }

  const entry: ActiveEntry = {
    node,
    registryKey,
    offset: zIndexOffset,
    bubbleHovered: false,
    position,
  };
  activeMap.set(id, entry);

  node.addEventListener('mouseenter', function onBubbleEnter() {
    entry.bubbleHovered = true;
  });
  node.addEventListener('mouseleave', function onBubbleLeave() {
    entry.bubbleHovered = false;
    // Nếu sentinel đã không còn visible (chuột đã rời trigger), xóa tooltip
    removeTooltipIfIdle(id);
  });

  document.body.appendChild(node);
}

/** sentinelActive = true khi IO đang thấy sentinel (chuột trên trigger/bridge) */
const sentinelActiveSet = new Set<string>();

function removeTooltipIfIdle(id: string) {
  const entry = activeMap.get(id);
  if (!entry) return;
  // Chỉ remove nếu cả sentinel lẫn bubble đều không có hover
  if (sentinelActiveSet.has(id) || entry.bubbleHovered) return;
  entry.node.remove();
  if (entry.offset >= 0) {
    release(entry.registryKey, entry.offset);
  }
  activeMap.delete(id);
}

function removeTooltip(id: string) {
  sentinelActiveSet.delete(id);
  removeTooltipIfIdle(id);
}

/**
 * Trick kết hợp CSS: sentinel element 1×1px ẩn bên trong wrapper.
 * Khi `:hover` CSS làm sentinel hiển thị (`display: block`), IntersectionObserver
 * phát hiện nó intersect viewport và gọi `showTooltip()`.
 * Không dùng JS event listener trên trigger — zero overhead.
 */
function getOrCreateObserver(): IntersectionObserver {
  if (!observer) {
    observer = new IntersectionObserver(
      entries => {
        for (const entry of entries) {
          const el = entry.target as HTMLElement;
          const id = el.dataset.id ?? '';
          const content = el.dataset.tip;
          const pos = (el.dataset.position ?? 'top') as 'top' | 'bottom' | 'left' | 'right';
          const colorClass = el.dataset.colorClass ?? '';
          const extraClass = el.dataset.extraClass;
          const customZIndex = el.dataset.customZIndex
            ? Number(el.dataset.customZIndex)
            : undefined;

          if (entry.isIntersecting) {
            sentinelActiveSet.add(id);
            const triggerEl = el.closest('[data-tt]') as HTMLElement | null;
            if (!triggerEl) continue;
            const customContent = customContentRegistry.get(id);
            showTooltip(
              id,
              triggerEl,
              content,
              customContent,
              pos,
              colorClass,
              extraClass,
              customZIndex,
            );
          } else {
            removeTooltip(id);
          }
        }
      },
      { threshold: 0 },
    );
  }
  return observer;
}

// ─── Tooltip — unified entry point ──────────────────────────────────────────

export const Tooltip: Component<TooltipProps> = p => {
  return (
    <Show when={!p.hidden} fallback={<>{p.children}</>}>
      <Switch fallback={<TooltipDefaultMain {...p} />}>
        <Match when={p.type === 'portal' || 'containerId' in p}>
          <TooltipPortalMain {...(p as TooltipPortalProps)} />
        </Match>
      </Switch>
    </Show>
  );
};

// ─── Default (IO-based) impl ─────────────────────────────────────────────────

const TooltipDefaultMain: Component<TooltipProps> = p => {
  p = mergeProps(
    {
      position: 'top' as const,
      color: 'neutral' as const,
    },
    p,
  );
  const id = createUniqueId();
  let sentinelRef!: HTMLDivElement;
  let customContentRef!: HTMLDivElement;

  onMount(() => {
    refCount++;
    sentinelRef.dataset.id = id;
    sentinelRef.dataset.tip = p.content ?? '';
    sentinelRef.dataset.position = p.position;
    sentinelRef.dataset.colorClass = getColor(p.color);
    if (p.class?.content) sentinelRef.dataset.extraClass = p.class.content;
    if (p.zIndex !== undefined) sentinelRef.dataset.customZIndex = String(p.zIndex);
    if (p.customContent && customContentRef?.firstElementChild) {
      customContentRegistry.set(id, customContentRef.firstElementChild);
    }
    getOrCreateObserver().observe(sentinelRef);
  });

  onCleanup(function cleanupTooltipRegistration() {
    observer?.unobserve(sentinelRef);
    removeTooltip(id);
    customContentRegistry.delete(id);
    refCount--;
    if (refCount === 0 && observer) {
      observer.disconnect();
      observer = null;
    }
  });

  return (
    <div
      ref={el => (el.dataset.tt = '')}
      class={cn('too07', p.class?.root)}
      data-pos={p.position ?? 'top'}
    >
      <div ref={sentinelRef} class="too08" />
      {p.children as JSX.Element}
      {p.customContent && (
        <div ref={customContentRef} class="hidden">
          {p.customContent}
        </div>
      )}
    </div>
  );
};

// ═══════════════════════════════════════════════════════════════════════════
// TOOLTIP PORTAL — Event-delegation mode
// ═══════════════════════════════════════════════════════════════════════════

/**
 * SINGLETON PORTAL BUBBLE — Thiết kế có chủ đích.
 * Signal ở module scope vì toàn bộ hệ thống tooltip portal chỉ có
 * DUY NHẤT 1 bubble tồn tại trong DOM tại bất kỳ thời điểm nào.
 */
const [portalBubbleStyle, setPortalBubbleStyle] = createSignal<
  import('solid-js').JSX.CSSProperties
>({});

type TooltipEntry = {
  setHovered: (v: boolean) => void;
  updateCoords: () => void;
};

type ContainerState = {
  count: number;
  entries: Map<string, TooltipEntry>;
};

const containerMap = new WeakMap<Element, ContainerState>();

type ListenerPair = { over: (e: Event) => void; out: (e: Event) => void };
const listenerMap = new WeakMap<Element, ListenerPair>();

function makeMouseOver(state: ContainerState) {
  return (e: Event) => {
    const el = (e.target as Element).closest('[tt]');
    if (!el) return;
    const tt = el.getAttribute('tt')!;
    const entry = state.entries.get(tt);
    if (entry) {
      entry.updateCoords();
      entry.setHovered(true);
    }
  };
}

function makeMouseOut(state: ContainerState) {
  return (e: Event) => {
    const el = (e.target as Element).closest('[tt]');
    if (!el) return;
    const tt = el.getAttribute('tt')!;
    const related = (e as MouseEvent).relatedTarget as Element | null;
    if (related && el.contains(related)) return;
    const entry = state.entries.get(tt);
    if (entry) entry.setHovered(false);
  };
}

function attachToContainer(root: Element, state: ContainerState) {
  const over = makeMouseOver(state);
  const out = makeMouseOut(state);
  listenerMap.set(root, { over, out });
  root.addEventListener('mouseover', over, { passive: true });
  root.addEventListener('mouseout', out, { passive: true });
}

function detachFromContainer(root: Element) {
  const pair = listenerMap.get(root);
  if (!pair) return;
  root.removeEventListener('mouseover', pair.over);
  root.removeEventListener('mouseout', pair.out);
  listenerMap.delete(root);
}

function calcPortalStyle(
  el: HTMLElement,
  position: 'top' | 'bottom' | 'left' | 'right',
): import('solid-js').JSX.CSSProperties {
  const r = el.getBoundingClientRect();
  const OFFSET_PX = 8;

  if (position === 'top') {
    return {
      left: `${r.left + r.width / 2}px`,
      top: `${r.top - OFFSET_PX}px`,
      transform: 'translateX(-50%) translateY(-100%)',
    };
  } else if (position === 'bottom') {
    return {
      left: `${r.left + r.width / 2}px`,
      top: `${r.bottom + OFFSET_PX}px`,
      transform: 'translateX(-50%)',
    };
  } else if (position === 'left') {
    return {
      left: `${r.left - OFFSET_PX}px`,
      top: `${r.top + r.height / 2}px`,
      transform: 'translateX(-100%) translateY(-50%)',
    };
  } else {
    return {
      left: `${r.right + OFFSET_PX}px`,
      top: `${r.top + r.height / 2}px`,
      transform: 'translateY(-50%)',
    };
  }
}

const TooltipPortalMain: Component<TooltipPortalProps> = p => {
  const id = createUniqueId();
  p = mergeProps(
    {
      position: 'top' as const,
      color: 'neutral' as const,
    },
    p,
  );

  const [isHovered, setIsHovered] = createSignal(false);

  const onTriggerMount = (el: HTMLDivElement) => {
    const position = p.position ?? 'top';
    const updateCoords = () => setPortalBubbleStyle(calcPortalStyle(el, position));
    el.setAttribute('tt', id);

    const handle = { cancelled: false, doCleanup: undefined as (() => void) | undefined };

    const register = () => {
      if (handle.cancelled) return;

      const root = document.getElementById(p.containerId);
      if (!root) return;

      let state = containerMap.get(root);
      if (!state) {
        state = { count: 0, entries: new Map() };
        containerMap.set(root, state);
      }
      state.entries.set(id, { setHovered: setIsHovered, updateCoords });
      state.count += 1;
      if (state.count === 1) attachToContainer(root, state);

      handle.doCleanup = () => {
        const s = containerMap.get(root);
        if (!s) return;
        s.entries.delete(id);
        s.count -= 1;
        el.removeAttribute('tt');
        if (s.count === 0) {
          detachFromContainer(root);
          containerMap.delete(root);
        }
      };
    };

    queueMicrotask(register);
    onCleanup(function cancelAndDetachTrigger() {
      handle.cancelled = true;
      handle.doCleanup?.();
    });
  };

  return (
    <div
      ref={onTriggerMount}
      class={cn(
        'too01',
        tooltipVariants({ color: p.color, position: p.position }),
        getColor(p.color),
        'too04',
        p.class?.root,
      )}
      {...(p.content && !p.customContent && { ['data-tip']: p.content })}
    >
      <Switch>
        <Match when={p.content}>
          <ZIndex
            type={ZIndexType.TOOLTIP}
            open={isHovered()}
            position={portalBubbleStyle()}
            class={cn('too05', getColor(p.color), p.class?.content)}
            blockScroll={false}
            customValue={p.zIndex}
          >
            {p.content}
          </ZIndex>
        </Match>
        <Match when={p.customContent}>
          <ZIndex
            type={ZIndexType.TOOLTIP}
            open={isHovered()}
            position={portalBubbleStyle()}
            class={cn('too05', p.class?.content)}
            customValue={p.zIndex}
          >
            {p.customContent}
          </ZIndex>
        </Match>
      </Switch>
      {p.children as JSX.Element}
    </div>
  );
};
